const TextField = ({label, name, value} : any) => {

    return (
        <div className="col-3">
            <label className="col-form-label">
                {label}<input className="form-control" title={label} type="text" value={value} name={name}></input>        
            </label>
        </div>
    )
}

export default TextField;
